                  return date === item.timestamp.split(" ")[0] ? (
                    content === item.id ? (
                      <button
                        key={item.id}
                        className="bg-[#845EC2] text-white w-full p-[10px] rounded-md flex flex-row items-center justify-center mt-[10px] mb-[10px]"
