        <div className="mt-[10px] text-white text-[18px] font-thin">
          gokulhk278@gmail.com
        </div>
        <Link to="/" className="mt-[10px] h-[8vh] bg-[#FF8066] text-[18px] text-white w-[100%] flex justify-center items-center rounded-md">
          Logout
        </Link>
      </div>
    </div>
  );
